SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_fin_vourcher_head ON sc_fin_vourcher_head CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_fin_vourcher_head() RETURNS trigger AS $BODY$
BEGIN
--return ;
  --//--Insert  
  if coalesce(OLD.vourcher_no::text, '') = '' and (NEW.vourcher_no IS NOT NULL AND NEW.vourcher_no::text <> '') then
    if (pka.auto_entry) then
      NEW.entry_branch := current_setting('app.login_br', true);
      --การเงินรับไปแล้ว แต่มายกเลิกออก แล้วให้ เสมือนยกเลิก
      if coalesce(NEW.entry_id::text, '') = ''  then
        NEW.entry_id := current_setting('app.login_id', true);
      end if;
      NEW.entry_date := statement_timestamp();
      NEW.entry_fin := current_setting('app.login_id', true);
    end if;
    NEW.shot_app := pka_com.getattrib_app('shot_app');
    -- 1 เป็นรายการที่รับ/จ่ายเงินโดย ทำรายการจากฝ่ายอื่นแล้วมารับ/จ่ายเงินที่การเงิน
    if coalesce(trim(both NEW.counter_split)::text, '') = '' then NEW.counter_split := pka_fin_posttofin.fp_counter_split;end if;
    -- 20090918 141338
    /*เพื่อระบุว่าใบสำคัญนี้ได้ ... ตั้งหนี้เมื่อผ่านรายการไป journal แต่ เพระเมื่อยกเลิก journal จะไปยกเลิกการตั้งหนี้ให้ด้วย*/

    if coalesce(NEW.create_loan::text, '') = '' or NEW.create_loan != '1' then NEW.create_loan := '0';end if;
  end if;
  --//--Change 
  if OLD.money_accept = '0' and NEW.money_accept = '1' then
    -- มีการกำหนดสถานะรับเงิน
    NEW.money_accept_findate := pka_fin_daily.fp_finance_date; -- วันที่การเงิน ณ วันที่ทำรายการรับเงิน
    NEW.money_accept_time := statement_timestamp(); -- วันเวลาที่ทำรายการรับเงิน
    NEW.money_accept_br := pka_com_function.fp_login_br; -- สาขาที่ทำรายการรับเงิน
    NEW.money_accept_pc := pka_com_function.fp_login_pc;-- เครื่องที่ทำรายการรับเงิน
  end if;
  --//--Default
  if coalesce(NEW.adjust_status::text, '') = '' or NEW.adjust_status != '1' then NEW.adjust_status := '0';end if;
  if coalesce(NEW.cancel_status::text, '') = '' or NEW.cancel_status != '1' then NEW.cancel_status := '0';end if;
  if OLD.cancel_status = '0' and NEW.cancel_status = '1' then
        NEW.cancel_id := current_setting('app.login_id', true);
        NEW.cancel_date := statement_timestamp();
        NEW.cancel_branch := current_setting('app.login_br', true);
  end if;

  if coalesce(NEW.cheque_install::text, '') = '' or NEW.cheque_install != 'Y' then NEW.cheque_install := 'N';end if;
  if coalesce(NEW.cheque_printable::text, '') = '' or NEW.cheque_printable != '1' then NEW.cheque_printable := '0';end if;
  if coalesce(trim(both NEW.fin_book)::text, '') = '' then NEW.fin_book := '0';end if;
  if coalesce(NEW.money_accept::text, '') = '' or NEW.money_accept != '1' then NEW.money_accept := '0';end if;
  if coalesce(NEW.post_journal::text, '') = '' or NEW.post_journal != '1' then NEW.post_journal := '0';end if;
  if coalesce(NEW.post_system::text, '') = '' or NEW.post_system != '1' then NEW.post_system := '0';end if;
  if coalesce(NEW.vourcher_type::text, '') = '' or NEW.vourcher_type != 'P' then NEW.vourcher_type := 'R';end if;
  if NEW.vourcher_type = 'R' then
    if coalesce(NEW.vourcher_group::text, '') = '' or NEW.vourcher_group  = ' ' then  NEW.vourcher_group := 'FINREC';end if;
    if coalesce(NEW.ref_system::text, '') = '' or NEW.ref_system  = ' ' then  NEW.ref_system := 'FIN';end if;
  end if;
  if NEW.vourcher_type = 'P' then
    if coalesce(NEW.vourcher_group::text, '') = '' or NEW.vourcher_group  = ' ' then  NEW.vourcher_group := 'FINPAY';end if;
    if coalesce(NEW.ref_system::text, '') = '' or NEW.ref_system  = ' ' then  NEW.ref_system := 'FIN';end if;
    --FMRADJ  ปรับปรุงรายการเงินรอจ่ายคืน ใช้วันที่ ตัดจ่าย จากการคีย์ตอนปรับปรุง ไม่เป็นไรเพราะไม่ลิงค์บัญชี แค่ต้องการรายงานถูกต้อง
    if  NEW.vourcher_group  = 'FMRADJ' then  NEW.journal_date := NEW.operate_date;end if;
  end if;
  if coalesce(NEW.blink_status::text, '') = '' or NEW.blink_status != '1' then NEW.blink_status := '0';end if;
  if coalesce(NEW.cheque_post::text, '') = '' then NEW.cheque_post := 0;end if;
  if coalesce(NEW.cheque_total::text, '') = '' then NEW.cheque_total := 0;end if;
  if coalesce(NEW.money_return_wait::text, '') = '' then NEW.money_return_wait := 0;end if;
  if coalesce(NEW.post_open_no::text, '') = '' then NEW.post_open_no := 0;end if;
  if coalesce(NEW.vourcher_value::text, '') = '' then NEW.vourcher_value := 0;end if;
  if coalesce(NEW.cheque_paid::text, '') = '' then NEW.cheque_paid :=0;end if;


RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_fin_vourcher_head() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_fin_vourcher_head
	BEFORE INSERT OR UPDATE ON sc_fin_vourcher_head FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_fin_vourcher_head();

